1	package cmd
2	
3	import (
4		"context"
5		"errors"
6		"fmt"
7		"strings"
8	
9		"github.com/DocumentDrivenDX/ddx/internal/agent"
10		tierescalation "github.com/DocumentDrivenDX/ddx/internal/agent/escalation"
11		"github.com/DocumentDrivenDX/ddx/internal/bead"
12		policyescalation "github.com/DocumentDrivenDX/ddx/internal/escalation"
13	)
14	
15	type escalationFloorFinder interface {
16		Next(actualPower int) (int, error)
17	}
18	
19	func isBudgetExhaustedFailure(report agent.ExecuteBeadReport) bool {
20		return strings.Contains(report.Detail, agent.RateLimitBudgetExhaustedReason)
21	}
22	
23	func nextEscalationFloor(l escalationFloorFinder, actualPower int) (int, error) {
24		if l == nil {
25			return 0, tierescalation.ErrLadderExhausted
26		}
27		floor := actualPower
28		for {
29			next, err := l.Next(floor)
30			if err == nil {
31				return next, nil
32			}
33			var nvp *tierescalation.NoViableProviderError
34			if errors.As(err, &nvp) {
35				floor = nvp.Floor
36				continue
37			}
38			return 0, err
39		}
40	}
41	
42	func highestViableEscalationFloor(l escalationFloorFinder) (int, error) {
43		if l == nil {
44			return 0, tierescalation.ErrLadderExhausted
45		}
46		floor := 0
47		highest := 0
48		for {
49			next, err := nextEscalationFloor(l, floor)
50			if err != nil {
51				if errors.Is(err, tierescalation.ErrLadderExhausted) && highest > 0 {
52					return highest, nil
53				}
54				return 0, err
55			}
56			highest = next
57			floor = next
58		}
59	}
60	
61	func investigationRetryInitialMinPower(b *bead.Bead, baseMinPower, maxPower int, ladder escalationFloorFinder) (int, agent.ExecuteBeadReport, bool) {
62		// Numeric hint: written by the no-changes smart-retry path one step at a time.
63		if floor, ok := numericTierFloorHint(b); ok {
64			if baseMinPower > floor {
65				return baseMinPower, smartRouteUnavailableReport(b, baseMinPower, maxPower, nil), true
66			}
67			if maxPower > 0 && floor >= maxPower {
68				return baseMinPower, smartRouteUnavailableReport(b, floor, maxPower, nil), true
69			}
70			return floor, agent.ExecuteBeadReport{}, false
71		}
72		// Tier-name hint: written by the review-triage path; jump to highest viable.
73		if tier, ok := triageTierHint(b); !ok || tier != policyescalation.TierSmart {
74			return baseMinPower, agent.ExecuteBeadReport{}, false
75		}
76		floor, err := highestViableEscalationFloor(ladder)
77		if err != nil {
78			return baseMinPower, smartRouteUnavailableReport(b, baseMinPower, maxPower, err), true
79		}
80		if baseMinPower > floor {
81			return baseMinPower, smartRouteUnavailableReport(b, baseMinPower, maxPower, nil), true
82		}
83		if maxPower > 0 && floor >= maxPower {
84			return baseMinPower, smartRouteUnavailableReport(b, floor, maxPower, nil), true
85		}
86		return floor, agent.ExecuteBeadReport{}, false
87	}
88	
89	// numericTierFloorHint returns the numeric MinPower floor stored by the
90	// no-changes smart-retry path, which advances one ladder step at a time.
91	// Tier-name string hints (from the review-triage path) are not matched here.
92	func numericTierFloorHint(b *bead.Bead) (int, bool) {
93		if b == nil || b.Extra == nil {
94			return 0, false
95		}
96		raw, ok := b.Extra[agent.TriageTierHintKey]
97		if !ok {
98			return 0, false
99		}
100		switch v := raw.(type) {
101		case int:
102			return v, v > 0
103		case int64:
104			return int(v), int(v) > 0
105		case float64:
106			return int(v), int(v) > 0
107		default:
108			return 0, false
109		}
110	}
111	
112	func triageTierHint(b *bead.Bead) (policyescalation.ModelTier, bool) {
113		if b == nil || b.Extra == nil {
114			return "", false
115		}
116		raw, ok := b.Extra[agent.TriageTierHintKey]
117		if !ok {
118			return "", false
119		}
120		switch strings.ToLower(strings.TrimSpace(fmt.Sprint(raw))) {
121		case string(policyescalation.TierSmart):
122			return policyescalation.TierSmart, true
123		case string(policyescalation.TierStandard):
124			return policyescalation.TierStandard, true
125		case string(policyescalation.TierCheap):
126			return policyescalation.TierCheap, true
127		default:
128			return "", false
129		}
130	}
131	
132	func smartRouteUnavailableReport(b *bead.Bead, minPower, maxPower int, cause error) agent.ExecuteBeadReport {
133		beadID := ""
134		if b != nil {
135			beadID = b.ID
136		}
137		detail := fmt.Sprintf("smart retry route unavailable: no viable routing candidate satisfies requested MinPower %d", minPower)
138		if maxPower > 0 {
139			detail += fmt.Sprintf(" and MaxPower %d", maxPower)
140		}
141		if cause != nil {
142			detail += ": " + cause.Error()
143		}
144		return agent.ExecuteBeadReport{
145			BeadID:        beadID,
146			Status:        agent.ExecuteBeadStatusExecutionFailed,
147			Detail:        detail,
148			OutcomeReason: agent.FailureModeNoViableProvider,
149		}
150	}
151	
152	func runEscalatingSingleTierAttempts(
153		ctx context.Context,
154		initialMinPower int,
155		ladder escalationFloorFinder,
156		attempt func(context.Context, int) (agent.ExecuteBeadReport, error),
157		recordAttempt func(agent.ExecuteBeadReport),
158	) (agent.ExecuteBeadReport, error) {
159		minPower := initialMinPower
160		for {
161			report, err := attempt(ctx, minPower)
162			if recordAttempt != nil && report.BeadID != "" {
163				recordAttempt(report)
164			}
165			if err != nil {
166				return report, err
167			}
168			if report.Disrupted || isBudgetExhaustedFailure(report) || !policyescalation.ShouldEscalate(report.Status) || policyescalation.IsInfrastructureFailure(report.Status, report.Detail) {
169				return report, nil
170			}
171			basis := minPower
172			if report.ActualPower > 0 {
173				basis = report.ActualPower
174			}
175			nextPower, nextErr := nextEscalationFloor(ladder, basis)
176			if nextErr != nil {
177				return report, nil
178			}
179			minPower = nextPower
180		}
181	}
