8	func TestIsInfrastructureFailure(t *testing.T) {
9		tests := []struct {
10			name   string
11			status string
12			detail string
13			want   bool
14		}{
15			{"structural validation is not infrastructure", "structural_validation_failed", "anything 502", false},
16			{"escalatable + empty detail returns false", "execution_failed", "", false},
17			{"escalatable + plain test failure is not infrastructure", "execution_failed", "TestFoo failed: assertion error", false},
18			{"escalatable + 502 from provider is infrastructure", "execution_failed", `provider error: POST "http://bragi:1234/v1/chat/completions": 502 Bad Gateway`, true},
19			{"escalatable + 503 service unavailable is infrastructure", "execution_failed", "503 Service Unavailable", true},
20			{"escalatable + connection refused is infrastructure", "execution_failed", "dial tcp 127.0.0.1:1234: connect: connection refused", true},
21			{"escalatable + no such host is infrastructure", "execution_failed", "dial tcp: lookup vidar: no such host", true},
22			{"escalatable + context deadline is infrastructure", "execution_failed", "context deadline exceeded", true},
23			{"escalatable + rate limit is infrastructure (operator-fixable)", "execution_failed", "429 Too Many Requests: rate limit reached", true},
24			{"escalatable + auth failure is infrastructure", "execution_failed", "401 Unauthorized: invalid api key", true},
25			{"escalatable + binary missing is infrastructure", "execution_failed", `exec: "claude": executable file not found in $PATH`, true},
26			{"escalatable + fizeau routing failure is infrastructure", "execution_failed", "ResolveRoute: no viable routing candidate: 3 candidates rejected", true},
27			{"case-insensitive match", "execution_failed", "BAD GATEWAY", true},
28			{"no_changes never infrastructure regardless of detail", "no_changes", "agent ran fine, no edits", false},
29			{"post_run_check_failed: gate failure is not infrastructure", "post_run_check_failed", "gate verify-tests exited with status 1", false},
30		}
31		for _, tt := range tests {
32			t.Run(tt.name, func(t *testing.T) {
33				if got := IsInfrastructureFailure(tt.status, tt.detail); got != tt.want {
34					t.Errorf("IsInfrastructureFailure(%q, %q) = %v, want %v",
35						tt.status, tt.detail, got, tt.want)
36				}
37			})
38		}
39	}
