67	// TestCostCapTracker_DisabledWhenMaxZero asserts MaxUSD<=0 is a kill
68	// switch — no Add ever trips Tripped, even at huge accumulated values.
69	func TestCostCapTracker_DisabledWhenMaxZero(t *testing.T) {
70		tr := NewCostCapTracker(0, func(string) bool { return true })
71		tr.Add("openrouter", 1000.0)
72		if _, capped := tr.Tripped(); capped {
73			t.Fatalf("Tripped should always be false when MaxUSD=0")
