77	// TestCostCapTracker_AddRespectsLookup asserts that Add ignores cost
78	// reports from harnesses whose Lookup returns false, e.g. local /
79	// subscription providers — they must never push the tracker over the
80	// cap.
81	func TestCostCapTracker_AddRespectsLookup(t *testing.T) {
82		tr := NewCostCapTracker(10.0, func(name string) bool {
83			return name == "openrouter"
84		})
85		tr.Add("claude", 100.0) // subscription — must not count
86		tr.Add("local-llama", 100.0)
87		if got := tr.Spent(); got != 0 {
88			t.Fatalf("Spent after non-billed adds = %.2f, want 0", got)
89		}
90		if _, capped := tr.Tripped(); capped {
91			t.Fatalf("non-billed adds must not trip the cap")
92		}
93		tr.Add("openrouter", 5.0)
94		if got := tr.Spent(); got != 5.0 {
95			t.Fatalf("Spent after billed add = %.2f, want 5.0", got)
96		}
97		if _, capped := tr.Tripped(); capped {
98			t.Fatalf("Tripped at $5 with $10 cap should be false")
99		}
100		tr.Add("openrouter", 6.0)
101		if got := tr.Spent(); got != 11.0 {
102			t.Fatalf("Spent after second billed add = %.2f, want 11.0", got)
103		}
104		detail, capped := tr.Tripped()
105		if !capped {
106			t.Fatalf("Tripped at $11 with $10 cap should be true")
107		}
108		if !strings.Contains(detail, "$11.00") || !strings.Contains(detail, "$10.00") {
109			t.Fatalf("Tripped detail missing dollar values: %q", detail)
110		}
111	}
