130	// TestCostCapTracker_NilLookupCountsByDefault asserts that a nil
131	// Lookup is treated as "count by default" — the safe option for
132	// callers that have not wired up harness-info resolution.
133	func TestCostCapTracker_NilLookupCountsByDefault(t *testing.T) {
134		tr := NewCostCapTracker(5.0, nil)
135		tr.Add("anything", 6.0)
136		if _, capped := tr.Tripped(); !capped {
137			t.Fatalf("nil Lookup should count by default; cap should trip")
138		}
139	}
