141	// TestCostCapTracker_ConcurrentSafe runs many goroutines hammering
142	// Add/Tripped/Spent concurrently — the test must not race (run with
143	// -race) and the final spent must be the deterministic sum.
144	func TestCostCapTracker_ConcurrentSafe(t *testing.T) {
145		tr := NewCostCapTracker(10000.0, func(string) bool { return true })
146		var wg sync.WaitGroup
147		for i := 0; i < 50; i++ {
148			wg.Add(1)
149			go func() {
150				defer wg.Done()
151				for j := 0; j < 20; j++ {
152					tr.Add("openrouter", 0.5)
153					_, _ = tr.Tripped()
154					_ = tr.Spent()
155				}
156			}()
157		}
158		wg.Wait()
159		want := 50.0 * 20.0 * 0.5
160		if got := tr.Spent(); got != want {
161			t.Fatalf("Spent after concurrent Adds = %.2f, want %.2f", got, want)
162		}
163	}
