13	// These tests exercise the cost-cap and infrastructure-failure wiring used
14	// by runAgentExecuteLoop's executor closure. The closure itself is built
15	// inline (so it cannot be unit-tested directly), but we exercise the same
16	// composition pattern here against a fake inner attempt to assert:
17	//
18	//  1. When accumulated cost exceeds the cap, the next executor invocation
19	//     returns the cap-tripped error WITHOUT invoking the inner attempt.
20	//  2. Infrastructure failures do not escalate to a smart tier — the tier
21	//     loop short-circuits with a deferred RetryAfter.
22	//
23	// The patterns mirror the closures in cli/cmd/agent_cmd.go (ddx-785d02f7).
24	
25	// fakeAttempt records calls and returns a configured sequence of reports.
26	type fakeAttempt struct {
27		calls   atomic.Int32
28		reports []agent.ExecuteBeadReport
29	}
30	
31	func (f *fakeAttempt) next(_ string) agent.ExecuteBeadReport {
32		idx := f.calls.Add(1) - 1
33		if int(idx) >= len(f.reports) {
34			return f.reports[len(f.reports)-1]
35		}
36		return f.reports[idx]
37	}
38	
39	// buildCostCappedExecutor mirrors the outer-executor wrapping done in
40	// runAgentExecuteLoop: cap check at the top, inner attempt, accumulate,
41	// cap check on the way out. Used by the tests below.
42	func buildCostCappedExecutor(tracker *escalation.CostCapTracker, inner func(beadID string) agent.ExecuteBeadReport) agent.ExecuteBeadExecutorFunc {
43		return func(ctx context.Context, beadID string) (agent.ExecuteBeadReport, error) {
44			if detail, capped := tracker.Tripped(); capped {
45				return agent.ExecuteBeadReport{
46					BeadID: beadID,
47					Status: agent.ExecuteBeadStatusExecutionFailed,
48					Detail: detail,
49				}, nil
50			}
51			report := inner(beadID)
52			tracker.Add(report.Harness, report.CostUSD)
53			if detail, capped := tracker.Tripped(); capped {
54				return agent.ExecuteBeadReport{
55					BeadID: beadID,
56					Status: agent.ExecuteBeadStatusExecutionFailed,
57					Detail: detail,
58				}, nil
59			}
60			return report, nil
61		}
62	}
63	
64	// TestExecuteLoopCostCap_ShortCircuitsAfterCap asserts the cost cap halts
65	// the queue: once accumulated billed cost reaches the cap, the next
66	// executor call returns the cap-tripped status without invoking the
67	// inner attempt.
68	func TestExecuteLoopCostCap_ShortCircuitsAfterCap(t *testing.T) {
69		tracker := escalation.NewCostCapTracker(10.0, func(string) bool { return true })
70	
71		fake := &fakeAttempt{
72			reports: []agent.ExecuteBeadReport{
73				{BeadID: "ddx-1", Harness: "openrouter", Status: agent.ExecuteBeadStatusSuccess, CostUSD: 6.0},
74				{BeadID: "ddx-2", Harness: "openrouter", Status: agent.ExecuteBeadStatusSuccess, CostUSD: 6.0},
75				// Should never be reached.
76				{BeadID: "ddx-3", Harness: "openrouter", Status: agent.ExecuteBeadStatusSuccess, CostUSD: 1.0},
77			},
78		}
79		exec := buildCostCappedExecutor(tracker, fake.next)
80	
81		// First call: $6 < $10 cap — succeeds and accumulates.
82		r1, err := exec(context.Background(), "ddx-1")
83		if err != nil {
84			t.Fatalf("call 1 err = %v", err)
85		}
86		if r1.Status != agent.ExecuteBeadStatusSuccess {
87			t.Fatalf("call 1 status = %s, want success", r1.Status)
88		}
89	
90		// Second call: accumulates to $12 >= $10 cap. Returns success but
91		// cap is now tripped — but wait, the post-attempt cap check fires,
92		// returning the cap-tripped report instead of the success report.
93		r2, err := exec(context.Background(), "ddx-2")
94		if err != nil {
95			t.Fatalf("call 2 err = %v", err)
96		}
97		if r2.Status != agent.ExecuteBeadStatusExecutionFailed {
98			t.Fatalf("call 2 should have tripped post-attempt cap; status = %s", r2.Status)
99		}
100		if !strings.Contains(r2.Detail, "cost cap reached") {
101			t.Fatalf("call 2 detail missing cost-cap message: %q", r2.Detail)
102		}
103	
104		callsBefore := fake.calls.Load()
105	
106		// Third call: cap-on-entry check trips IMMEDIATELY, inner attempt
107		// is NOT invoked.
108		r3, err := exec(context.Background(), "ddx-3")
109		if err != nil {
110			t.Fatalf("call 3 err = %v", err)
111		}
112		if r3.Status != agent.ExecuteBeadStatusExecutionFailed {
113			t.Fatalf("call 3 should be cap-tripped; status = %s", r3.Status)
114		}
115		if r3.BeadID != "ddx-3" {
116			t.Fatalf("call 3 beadID = %s, want ddx-3", r3.BeadID)
117		}
118		if got := fake.calls.Load(); got != callsBefore {
119			t.Fatalf("cap-on-entry must NOT invoke inner attempt; calls went %d -> %d", callsBefore, got)
120		}
121	}
122	
123	// TestExecuteLoopCostCap_LocalProvidersDoNotCount asserts that local
124	// and subscription providers' CostUSD never accumulates against the
125	// cap, even if they report a non-zero cost field.
126	func TestExecuteLoopCostCap_LocalProvidersDoNotCount(t *testing.T) {
127		// Lookup says only "openrouter" counts.
128		tracker := escalation.NewCostCapTracker(10.0, func(name string) bool {
129			return name == "openrouter"
130		})
131	
132		fake := &fakeAttempt{
133			reports: []agent.ExecuteBeadReport{
134				{BeadID: "ddx-a", Harness: "claude", Status: agent.ExecuteBeadStatusSuccess, CostUSD: 100.0},
135				{BeadID: "ddx-b", Harness: "qwen-local", Status: agent.ExecuteBeadStatusSuccess, CostUSD: 100.0},
136				{BeadID: "ddx-c", Harness: "openrouter", Status: agent.ExecuteBeadStatusSuccess, CostUSD: 1.0},
137			},
138		}
139		exec := buildCostCappedExecutor(tracker, fake.next)
140	
141		for _, id := range []string{"ddx-a", "ddx-b", "ddx-c"} {
142			r, err := exec(context.Background(), id)
143			if err != nil {
144				t.Fatalf("call %s err = %v", id, err)
145			}
146			if r.Status != agent.ExecuteBeadStatusSuccess {
147				t.Fatalf("call %s status = %s, want success (local/sub providers must not trip the cap)", id, r.Status)
148			}
149		}
150		if got := tracker.Spent(); got != 1.0 {
151			t.Fatalf("Spent = %.2f, want 1.0 — only openrouter should contribute", got)
152		}
153	}
