1831	func formatAttemptRouteEconomics(attempt agent.ExecuteBeadReport) string {
1832		if attempt.Harness == "" && attempt.Provider == "" && attempt.Model == "" {
1833			return ""
1834		}
1835		parts := []string{}
1836		if attempt.Harness != "" {
1837			parts = append(parts, "harness="+attempt.Harness)
1838		}
1839		if attempt.Provider != "" {
1840			parts = append(parts, "provider="+attempt.Provider)
1841		}
1842		if attempt.Model != "" {
1843			parts = append(parts, "model="+attempt.Model)
1844		}
1845		power := attempt.PredictedPower
1846		if power == 0 {
1847			power = attempt.ActualPower
1848		}
1849		if power > 0 {
1850			parts = append(parts, fmt.Sprintf("power=%d", power))
1851		}
1852		if attempt.PredictedSpeedTPS > 0 {
1853			parts = append(parts, fmt.Sprintf("speed=%.1f tok/s", attempt.PredictedSpeedTPS))
1854		}
1855		if attempt.PredictedCostUSDPer1kTokens > 0 {
1856			cost := fmt.Sprintf("cost=$%.6f/1k tok", attempt.PredictedCostUSDPer1kTokens)
1857			if attempt.PredictedCostSource != "" {
1858				cost += " source=" + attempt.PredictedCostSource
1859			}
1860			parts = append(parts, cost)
1861		} else if attempt.PredictedCostSource != "" {
1862			parts = append(parts, "cost_source="+attempt.PredictedCostSource)
1863		}
1864		return strings.Join(parts, " ")
1865	}
