1867	func writeExecuteLoopResult(w io.Writer, projectRoot string, result *agent.ExecuteBeadLoopResult, asJSON bool) error {
1868		if asJSON {
1869			payload := struct {
1870				ProjectRoot string `json:"project_root"`
1871				*agent.ExecuteBeadLoopResult
1872			}{
1873				ProjectRoot:           projectRoot,
1874				ExecuteBeadLoopResult: result,
1875			}
1876			enc := json.NewEncoder(w)
1877			enc.SetIndent("", "  ")
1878			return enc.Encode(payload)
1879		}
1880	
1881		if result.NoReadyWork && result.Attempts == 0 {
1882			writeNoReadyWorkSummary(w, projectRoot, result.NoReadyWorkDetail)
1883			writeQueueSnapshotTerminalSummary(w, result.QueueSnapshot)
1884			return nil
1885		}
1886	
1887		fmt.Fprintf(w, "\nproject: %s\n", projectRoot)
1888		writeWorkTerminalSummary(w, result)
1889		if result.Failures > 0 {
1890			fmt.Fprintf(w, "\nfailed:\n")
1891			for _, attempt := range result.Results {
1892				if attempt.Status != "success" {
1893					fmt.Fprintf(w, "  - %s: %s", attempt.BeadID, attempt.Detail)
1894					if attempt.PreserveRef != "" {
1895						fmt.Fprintf(w, " (preserved)")
1896					}
1897					fmt.Fprintln(w)
1898				}
1899			}
1900		}
1901		if result.NoReadyWork {
1902			fmt.Fprintln(w)
1903			writeNoReadyWorkSummary(w, "", result.NoReadyWorkDetail)
1904			writeQueueSnapshotTerminalSummary(w, result.QueueSnapshot)
1905		}
1906		return nil
1907	}
