1909	func writeWorkTerminalSummary(w io.Writer, result *agent.ExecuteBeadLoopResult) {
1910		closed, changed, alreadySatisfied := countWorkTerminalOutcomes(result)
1911		fmt.Fprintf(w, "worker exited: %s\n", workExitSummary(result))
1912		fmt.Fprintf(w, "attempts: %d  |  closed: %d  |  changed: %d  |  already-satisfied: %d  |  failures: %d\n",
1913			result.Attempts, closed, changed, alreadySatisfied, result.Failures)
1914	}
1915	
1916	func countWorkTerminalOutcomes(result *agent.ExecuteBeadLoopResult) (closed, changed, alreadySatisfied int) {
1917		for _, attempt := range result.Results {
1918			switch attempt.Status {
1919			case agent.ExecuteBeadStatusSuccess:
1920				closed++
1921				changed++
1922			case agent.ExecuteBeadStatusAlreadySatisfied:
1923				closed++
1924				alreadySatisfied++
1925			}
1926		}
1927		if closed == 0 && result.Successes > 0 {
1928			closed = result.Successes
1929		}
1930		return closed, changed, alreadySatisfied
1931	}
