1933	func workExitSummary(result *agent.ExecuteBeadLoopResult) string {
1934		switch result.ExitReason {
1935		case "drained":
1936			return "drained current execution-ready queue"
1937		case "once_complete":
1938			return "once complete"
1939		case "budget":
1940			return "budget reached"
1941		case "no_progress":
1942			return "no-progress policy stopped work"
1943		case "blocked":
1944			return "blocked waiting for external action"
1945		case "sigint", "sigterm", "context_cancelled":
1946			return "stopped by signal"
1947		case "fatal_config":
1948			return "fatal configuration error"
1949		case "preflight_failed":
1950			return "preflight failed"
1951		case "resource_exhausted":
1952			return "resource exhausted"
1953		case "routing_unavailable":
1954			return "routing unavailable"
1955		}
