9	func TestIsInfrastructureFailure(t *testing.T) {
10		tests := []struct {
11			name   string
12			status string
13			detail string
14			want   bool
15		}{
16			{"structural validation is not infrastructure", "structural_validation_failed", "anything 502", false},
17			{"escalatable + empty detail returns false", "execution_failed", "", false},
18			{"escalatable + plain test failure is not infrastructure", "execution_failed", "TestFoo failed: assertion error", false},
19			{"escalatable + 502 from provider is infrastructure", "execution_failed", `provider error: POST "http://bragi:1234/v1/chat/completions": 502 Bad Gateway`, true},
20			{"escalatable + 503 service unavailable is infrastructure", "execution_failed", "503 Service Unavailable", true},
21			{"escalatable + connection refused is infrastructure", "execution_failed", "dial tcp 127.0.0.1:1234: connect: connection refused", true},
22			{"escalatable + no such host is infrastructure", "execution_failed", "dial tcp: lookup vidar: no such host", true},
23			{"escalatable + context deadline is infrastructure", "execution_failed", "context deadline exceeded", true},
24			{"escalatable + rate limit is infrastructure (operator-fixable)", "execution_failed", "429 Too Many Requests: rate limit reached", true},
25			{"escalatable + auth failure is infrastructure", "execution_failed", "401 Unauthorized: invalid api key", true},
26			{"escalatable + binary missing is infrastructure", "execution_failed", `exec: "claude": executable file not found in $PATH`, true},
27			{"escalatable + fizeau routing failure is infrastructure", "execution_failed", "ResolveRoute: no viable routing candidate: 3 candidates rejected", true},
28			{"case-insensitive match", "execution_failed", "BAD GATEWAY", true},
29			{"no_changes never infrastructure regardless of detail", "no_changes", "agent ran fine, no edits", false},
30			{"post_run_check_failed: gate failure is not infrastructure", "post_run_check_failed", "gate verify-tests exited with status 1", false},
