79	// reports from harnesses whose Lookup returns false, e.g. local /
80	// subscription providers — they must never push the tracker over the
81	// cap.
82	func TestCostCapTracker_AddRespectsLookup(t *testing.T) {
83		tr := NewCostCapTracker(10.0, func(name string) bool {
84			return name == "openrouter"
85		})
86		tr.Add("claude", 100.0) // subscription — must not count
