95		if got := tr.Spent(); got != 5.0 {
96			t.Fatalf("Spent after billed add = %.2f, want 5.0", got)
97		}
98		if _, capped := tr.Tripped(); capped {
99			t.Fatalf("Tripped at $5 with $10 cap should be false")
100		}
101		tr.Add("openrouter", 6.0)
102		if got := tr.Spent(); got != 11.0 {
103			t.Fatalf("Spent after second billed add = %.2f, want 11.0", got)
104		}
