143	// Add/Tripped/Spent concurrently — the test must not race (run with
144	// -race) and the final spent must be the deterministic sum.
145	func TestCostCapTracker_ConcurrentSafe(t *testing.T) {
146		tr := NewCostCapTracker(10000.0, func(string) bool { return true })
147		var wg sync.WaitGroup
148		for i := 0; i < 50; i++ {
149			wg.Add(1)
150			go func() {
151				defer wg.Done()
152				for j := 0; j < 20; j++ {
153					tr.Add("openrouter", 0.5)
