155					_ = tr.Spent()
156				}
157			}()
158		}
159		wg.Wait()
160		want := 50.0 * 20.0 * 0.5
161		if got := tr.Spent(); got != want {
162			t.Fatalf("Spent after concurrent Adds = %.2f, want %.2f", got, want)
163		}
164	}
